class Solution:
    def isArraySpecial(self, nums: List[int]) -> bool:
        # If the array has 0 or 1 element, it's trivially special
        if len(nums) <= 1:
            return True

        # Check each adjacent pair for different parity
        for i in range(len(nums) - 1):
            if (nums[i] % 2) == (nums[i + 1] % 2):
                return False
        return True
